(function($){"use strict";class GHLMenuRouter{constructor(){this.menuItems={};this.currentHash="";this.init()}
init(){this.buildMenuMap();$(window).on("hashchange",()=>this.updateActiveMenuItem());this.updateActiveMenuItem();this.attachMenuClickHandlers()}
buildMenuMap(){const $submenuItems=$("#adminmenu .toplevel_page_ghl-crm-admin .wp-submenu a",);$submenuItems.each((index,element)=>{const $item=$(element);const href=$item.attr("href");if(href){const hashMatch=href.match(/#\/([\w-]*)/);if(hashMatch){const route=hashMatch[1]||"dashboard";if(!this.menuItems[route]){this.menuItems[route]=[]}
this.menuItems[route].push($item)}}});const $headerNavItems=$(".ghl-nav-tab[data-route]");$headerNavItems.each((index,element)=>{const $item=$(element);const route=$item.data("route");if(route){if(!this.menuItems[route]){this.menuItems[route]=[]}
this.menuItems[route].push($item)}})}
updateActiveMenuItem(){let hash=window.location.hash.replace(/^#\/?/,"")||"dashboard";const settingsTabs=typeof ghlCrmSpaConfig!=="undefined"&&ghlCrmSpaConfig.settings?ghlCrmSpaConfig.settings.tabs:["general","api","rest-api","webhooks","notifications","sync-options","role-tags","conversations","advanced","stats",];if(settingsTabs.includes(hash)){hash="settings"}
if(hash===this.currentHash){return}
this.currentHash=hash;Object.values(this.menuItems).forEach(($items)=>{if(Array.isArray($items)){$items.forEach(($item)=>{$item.removeClass("current active")})}else{$items.removeClass("current active")}});if(this.menuItems[hash]){const items=this.menuItems[hash];if(Array.isArray(items)){items.forEach(($item)=>{if($item.hasClass("ghl-nav-tab")){$item.addClass("active")}else{$item.addClass("current")}})}else{items.addClass("current")}}else{console.warn("No menu item found for hash:",hash)}
this.ensureParentExpanded()}
ensureParentExpanded(){const $parentMenuItem=$("#adminmenu .toplevel_page_ghl-crm-admin");$parentMenuItem.addClass("wp-has-current-submenu wp-menu-open");$parentMenuItem.removeClass("wp-not-current-submenu");$parentMenuItem.find("> a").addClass("wp-has-current-submenu")}
attachMenuClickHandlers(){Object.entries(this.menuItems).forEach(([route,$items])=>{const items=Array.isArray($items)?$items:[$items];items.forEach(($item)=>{$item.on("click",(e)=>{setTimeout(()=>{this.updateActiveMenuItem()},10)})})})}}
$(document).ready(function(){if($("#adminmenu .toplevel_page_ghl-crm-admin").length>0){new GHLMenuRouter()}})})(jQuery)